export type ImageKey = keyof typeof images;

// ---------------------------------------------------------------------------
// Bundled → CDN switch for lesson visuals (AGENTS.md "Lesson Visuals Rules")
//
// Lesson images are bundled in the APK today. When the library outgrows a sane
// APK size, move the (optimized) lesson visuals to a static CDN and set
// `EXPO_PUBLIC_LESSON_CDN_BASE`; each key then resolves to `<base>/<key>.webp`,
// which `expo-image` fetches + caches with no other code change. This file stays
// the single resolution point — flipping is a config change, not a code change.
// (See `image-pipeline/optimize-lesson-images.js` for the compression step and
// NOTES.md for the documented flip point.)
// ---------------------------------------------------------------------------

/** A source `expo-image` accepts: a bundled asset id, or a remote URL. */
export type ImageSource = number | { uri: string };

const LESSON_CDN_BASE = (process.env.EXPO_PUBLIC_LESSON_CDN_BASE ?? "").replace(/\/+$/, "");

/** True when lesson visuals are served from the CDN (remote) rather than bundled. */
export const lessonImagesAreRemote = LESSON_CDN_BASE.length > 0;

/**
 * Resolve a lesson-visual key to its source: a remote CDN URL when configured,
 * else the bundled asset. The single switch point for bundled → CDN; callers
 * (e.g. `FeedImage`) don't change.
 */
export function resolveLessonImage(key: ImageKey): ImageSource {
  if (lessonImagesAreRemote) return { uri: `${LESSON_CDN_BASE}/${key}.webp` };
  return images[key];
}
